<span class="line"><span style="color:#F8F8F2;">		h3</span><span style="color:#F92672;">=</span><span style="color:#F8F8F2;"> Host(</span><span style="color:#FD971F;font-style:italic;">hostname</span><span style="color:#F92672;">=</span><span style="color:#E6DB74;">&#39;test3&#39;</span><span style="color:#F8F8F2;">,</span><span style="color:#FD971F;font-style:italic;">ip_addr</span><span style="color:#F92672;">=</span><span style="color:#E6DB74;">&quot;192.168.1.1&quot;</span><span style="color:#F8F8F2;">,</span><span style="color:#FD971F;font-style:italic;">port</span><span style="color:#F92672;">=</span><span style="color:#AE81FF;">8080</span><span style="color:#F8F8F2;">)</span></span>
