<span class="line"><span style="color:#FD971F;font-style:italic;">	pool_size</span><span style="color:#F92672;"> =</span><span style="color:#AE81FF;"> 10</span><span style="color:#F8F8F2;">, </span><span style="color:#88846F;"># 连接池大小</span></span>
